package com.hospital.management.service.impl;import com.hospital.management.dao.*;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.validation.*;import org.junit.jupiter.api.*;import org.mockito.*;import java.time.*;import java.util.*;import static org.junit.jupiter.api.Assertions.*;import static org.mockito.ArgumentMatchers.*;import static org.mockito.Mockito.*;
class DoctorScheduleServiceImplTest{@Mock DoctorScheduleDao s;@Mock DoctorDao d;@Mock AuditLogDao a;AutoCloseable m;DoctorScheduleServiceImpl service;AuthenticatedUser admin=new AuthenticatedUser(1L,"a","a@x","ADMIN"),doctorUser=new AuthenticatedUser(2L,"d","d@x","DOCTOR");@BeforeEach void init(){m=MockitoAnnotations.openMocks(this);service=new DoctorScheduleServiceImpl(s,d,new DoctorScheduleValidator(),a);}@AfterEach void close()throws Exception{m.close();}@Test void adminCreateSuccess()throws Exception{when(d.findById(5L)).thenReturn(Optional.of(doctor()));when(s.create(any())).thenReturn(9L);assertTrue(service.createSchedule(form(),ctx(),admin).isSuccess());}@Test void doctorOwnCreateAndOtherDenied()throws Exception{when(d.findByUserId(2L)).thenReturn(Optional.of(doctor()));when(d.findById(5L)).thenReturn(Optional.of(doctor()));when(s.create(any())).thenReturn(9L);assertTrue(service.createSchedule(form(),ctx(),doctorUser).isSuccess());DoctorScheduleForm f=form();f.setDoctorId(6L);assertEquals(ServiceResult.Status.FORBIDDEN,service.createSchedule(f,ctx(),doctorUser).getStatus());}@Test void inactiveConflict()throws Exception{Doctor x=doctor();x.setStatus("INACTIVE");when(d.findById(5L)).thenReturn(Optional.of(x));assertEquals(ServiceResult.Status.CONFLICT,service.createSchedule(form(),ctx(),admin).getStatus());}@Test void overlapBlockedAndAudited()throws Exception{when(d.findById(5L)).thenReturn(Optional.of(doctor()));when(s.existsOverlap(anyLong(),anyString(),any(),any())).thenReturn(true);assertEquals(ServiceResult.Status.CONFLICT,service.createSchedule(form(),ctx(),admin).getStatus());verify(a).recordEvent(eq("DOCTOR_SCHEDULE_OVERLAP_BLOCKED"),any(),eq("DOCTOR_SCHEDULE"),any(),any(),any());}@Test void doctorCannotUpdateOthers()throws Exception{when(s.findById(9L)).thenReturn(Optional.of(schedule(6L)));when(d.findByUserId(2L)).thenReturn(Optional.of(doctor()));DoctorScheduleForm f=form();f.setScheduleId(9L);assertEquals(ServiceResult.Status.FORBIDDEN,service.updateSchedule(f,ctx(),doctorUser).getStatus());}@Test void deactivateSuccessAndAuditFailureSafe()throws Exception{when(s.findById(9L)).thenReturn(Optional.of(schedule(5L)));doThrow(new RuntimeException()).when(a).recordEvent(any(),any(),any(),any(),any(),any());assertTrue(service.deactivateSchedule(9L,ctx(),admin).isSuccess());}private Doctor doctor(){Doctor d=new Doctor();d.setDoctorId(5L);d.setUserId(2L);d.setStatus("ACTIVE");d.setUserStatus("ACTIVE");return d;}private DoctorSchedule schedule(Long id){DoctorSchedule s=new DoctorSchedule();s.setScheduleId(9L);s.setDoctorId(id);s.setDayOfWeek("MONDAY");s.setStartTime(LocalTime.of(9,0));s.setEndTime(LocalTime.of(11,0));return s;}private DoctorScheduleForm form(){DoctorScheduleForm f=new DoctorScheduleForm();f.setDoctorId(5L);f.setDayOfWeek("MONDAY");f.setStartTime("09:00");f.setEndTime("11:00");f.setSlotDurationMinutes("30");f.setAvailable(true);return f;}private AuditContext ctx(){return new AuditContext(1L,"ip","ua");}}
